&lt;Testtakers&gt;
  &lt;Metadata&gt;&lt;/Metadata&gt;
  &lt;Group id="Bsp_Group_StarS" label="Beispiel Gruppe StarS"&gt;
    &lt;Login mode="run-demo" name="fg65trd#hz" pw=""&gt;
      &lt;Booklet&gt;Demoheft_Technikrunde_GT&lt;/Booklet&gt;
